6	const dbUrl = process.env.DB_URL;
7	if (!dbUrl) {
8	    console.error("Missing DB_URL in .env");
9	    process.exit(1);
10	}
11	
12	const client = new Client({ connectionString: dbUrl });
13	
14	async function runSQL() {
15	    try {
16	        await client.connect();
17	        console.log("Connected to Supabase DB via pg.");
18	
19	        // Run the seed sql
20	        const sqlPath = path.join(__dirname, 'supabase', 'seed', 'cold_start_priors.sql');
21	        const sql = fs.readFileSync(sqlPath, 'utf8');
22	
23	        console.log("Applying cold_start_priors.sql...");
24	        await client.query(sql);
25	        console.log("Successfully applied priors.");
26	
27	        // Refresh the view
28	        console.log("Refreshing materialized view...");
29	        await client.query("REFRESH MATERIALIZED VIEW CONCURRENTLY mv_action_scores;");
30	        console.log("Materialized view refreshed.");
31	
32	    } catch (err) {
33	        console.error("Error executing SQL:", err);
34	        process.exit(1);
35	    } finally {
36	        await client.end();
37	    }
38	}
39	
40	runSQL();
