3	async function checkE2E() {
4	    console.log('--- LAYERINFINITE E2E VERIFICATION ---');
5	    let allPassed = true;
6	
7	    // 1. GET /v1/get-scores -> update_app is top recommendation
8	    try {
9	        const res = await fetch('http://localhost:3000/v1/get-scores?issue_type=payment_failed', {
10	            headers: { 'X-API-Key': 'key123', 'X-Customer-ID': 'a0000000-0000-0000-0000-000000000001' }
11	        });
12	        const json = await res.json();
13	        const topAction = json.top_action?.action_name;
14	        console.log(`1. GET /v1/get-scores -> Top Action: ${topAction}`);
15	        if (topAction !== 'update_app') {
16	            console.error('  -> FAILED: Expected update_app');
17	            allPassed = false;
18	        } else {
19	            console.log('  -> PASSED');
20	        }
21	    } catch (e) {
22	        console.error('  -> Error GET get-scores:', e.message);
23	        allPassed = false;
24	    }
25	
26	    // 2. POST /v1/admin/actions without auth -> 401
27	    try {
28	        const res = await fetch('http://localhost:3000/v1/admin/actions', { method: 'POST' });
29	        console.log(`2. POST /v1/admin/actions without auth -> Status: ${res.status}`);
30	        if (res.status !== 401) {
31	            console.error(`  -> FAILED: Expected 401, got ${res.status}`);
32	            allPassed = false;
33	        } else {
34	            console.log('  -> PASSED');
35	        }
36	    } catch (e) {
37	        console.error('  -> Error POST admin/actions:', e.message);
38	        allPassed = false;
39	    }
40	
41	    // 3. POST /v1/log-outcome with fake action -> 400 (not 422)
42	    try {
43	        const res = await fetch('http://localhost:3000/v1/log-outcome', {
44	            method: 'POST',
45	            headers: {
46	                'Content-Type': 'application/json',
47	                'X-API-Key': 'key123',
48	                'X-Agent-ID': 'd0000000-0000-0000-0000-000000000001',
49	                'X-Customer-ID': 'a0000000-0000-0000-0000-000000000001'
50	            },
51	            body: JSON.stringify({
52	                session_id: '00000000-0000-0000-0000-000000000123',
53	                action_name: 'fake_action_does_not_exist',
54	                issue_type: 'payment_failed',
55	                success: true
56	            })
57	        });
58	        console.log(`3. POST /v1/log-outcome fake action -> Status: ${res.status}`);
59	        if (res.status !== 400) {
60	            console.error(`  -> FAILED: Expected 400, got ${res.status}`);
61	            allPassed = false;
62	        } else {
63	            const json = await res.json();
64	            console.log(`     Error Code: ${json.error}`);
65	            console.log('  -> PASSED');
66	        }
67	    } catch (e) {
68	        console.error('  -> Error POST log-outcome:', e.message);
69	        allPassed = false;
70	    }
71	
72	    console.log('-------------------------------');
73	    if (allPassed) {
74	        console.log('ALL E2E CHECKS PASSED SUCCESSFULLY!');
75	    } else {
76	        console.log('SOME CHECKS FAILED.');
77	    }
78	}
79	
80	checkE2E();
