11	        const healthRes = await fetch(`${baseUrl}/health`);
12	        const healthBody = await healthRes.json();
13	        if (healthRes.status !== 200 || (healthBody.status !== "ok" && healthBody.status !== "degraded")) {
14	            throw new Error(`health check returned status ${healthRes.status}`);
15	        }
16	        console.log("✅ PASS: health endpoint");
17	
18	        const qRes = await fetch(`${baseUrl}/v1/get-scores?agent_id=smoke-test&issue_type=test`, {
19	            headers: { 'X-API-Key': apiKey }
20	        });
21	        
22	        if (qRes.status !== 200 && qRes.status !== 401 && qRes.status !== 404) {
23	            throw new Error(`get-scores returned status ${qRes.status}`);
24	        }
25	        if (!qRes.headers.get('Content-Type')?.includes('application/json')) {
26	            throw new Error(`get-scores invalid Content-Type`);
27	        }
28	        console.log("✅ PASS: get-scores endpoint reachable");
